import{_ as a,o as s,c as i,aj as t}from"./chunks/framework.DEEoir6m.js";const h=JSON.parse('{"title":"Plugin QGIS","description":"Installer et utiliser le plugin QGIS GISPulse — connexion au backend, dataset browser, jobs, OGC, MVT.","frontmatter":{"title":"Plugin QGIS","description":"Installer et utiliser le plugin QGIS GISPulse — connexion au backend, dataset browser, jobs, OGC, MVT."},"headers":[],"relativePath":"plugins/qgis.md","filePath":"plugins/qgis.md"}'),n={name:"plugins/qgis.md"};function l(r,e,o,u,d,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="plugin-qgis" tabindex="-1">Plugin QGIS <a class="header-anchor" href="#plugin-qgis" aria-label="Permalink to &quot;Plugin QGIS&quot;">​</a></h1><p>Le plugin QGIS GISPulse connecte QGIS à un backend GISPulse (local ou distant) pour parcourir les datasets, exécuter des règles et charger des layers via OGC API Features, PostGIS et MVT.</p><p><strong>Compatibilité :</strong> QGIS 3.28 – 4.x</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><h3 id="depuis-le-gestionnaire-d-extensions-qgis" tabindex="-1">Depuis le gestionnaire d&#39;extensions QGIS <a class="header-anchor" href="#depuis-le-gestionnaire-d-extensions-qgis" aria-label="Permalink to &quot;Depuis le gestionnaire d&#39;extensions QGIS&quot;">​</a></h3><ol><li>Dans QGIS : <strong>Extensions → Gérer et installer les extensions</strong></li><li>Rechercher <strong>GISPulse</strong></li><li>Cliquer <strong>Installer</strong></li></ol><h3 id="installation-manuelle-developpement" tabindex="-1">Installation manuelle (développement) <a class="header-anchor" href="#installation-manuelle-developpement" aria-label="Permalink to &quot;Installation manuelle (développement)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Cloner le dépôt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/gispulse/gispulse</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gispulse/clients/qgis</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Construire le plugin (crée gispulse_qgis.zip)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build_plugin.py</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Installer dans QGIS</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gispulse_qgis</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.local/share/QGIS/QGIS3/profiles/default/python/plugins/</span></span></code></pre></div><p>Activer le plugin dans <strong>Extensions → Gérer et installer les extensions → Installées</strong>.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Au premier démarrage, la boîte de dialogue de connexion s&#39;ouvre :</p><ol><li><strong>Server URL</strong> : URL de votre backend GISPulse (ex: <code>http://localhost:8001</code> ou <code>https://gispulse.exemple.com</code>)</li><li><strong>API Key</strong> : Clé API si votre serveur est sécurisé (laisser vide pour un serveur local sans auth)</li><li>Cliquer <strong>Test Connection</strong> pour vérifier</li><li><strong>OK</strong> pour valider</li></ol><p>Les paramètres sont sauvegardés dans les settings QGIS (chiffrés si une clé est définie).</p><h2 id="panneaux-disponibles" tabindex="-1">Panneaux disponibles <a class="header-anchor" href="#panneaux-disponibles" aria-label="Permalink to &quot;Panneaux disponibles&quot;">​</a></h2><p>Le plugin ajoute quatre panneaux accessibles via <strong>Vue → Panneaux</strong> :</p><h3 id="panneau-datasets" tabindex="-1">Panneau Datasets <a class="header-anchor" href="#panneau-datasets" aria-label="Permalink to &quot;Panneau Datasets&quot;">​</a></h3><ul><li>Liste les datasets enregistrés sur le serveur GISPulse</li><li>Upload d&#39;un fichier spatial directement depuis QGIS</li><li>Chargement d&#39;une layer en un clic : <ul><li><strong>OGC Features</strong> — layer vecteur via l&#39;API OGC (pagination automatique)</li><li><strong>MVT</strong> — tuiles vectorielles pour les gros volumes</li><li><strong>PostGIS</strong> — connexion directe si session PostGIS active (Pro)</li></ul></li><li>Prévisualisation des métadonnées (CRS, feature count, format)</li></ul><h3 id="panneau-jobs" tabindex="-1">Panneau Jobs <a class="header-anchor" href="#panneau-jobs" aria-label="Permalink to &quot;Panneau Jobs&quot;">​</a></h3><ul><li>Créer et exécuter des jobs sur un dataset sélectionné</li><li>Suivi en temps réel de l&#39;exécution (barre de progression)</li><li>Télécharger le résultat comme nouvelle layer QGIS</li><li>Historique des jobs récents</li></ul><h3 id="panneau-triggers-pro" tabindex="-1">Panneau Triggers (Pro) <a class="header-anchor" href="#panneau-triggers-pro" aria-label="Permalink to &quot;Panneau Triggers (Pro)&quot;">​</a></h3><ul><li>Voir et gérer les triggers actifs sur le serveur</li><li>Activer/désactiver un trigger</li><li>Voir les événements récents</li></ul><h3 id="panneau-scenarios-pro" tabindex="-1">Panneau Scenarios (Pro) <a class="header-anchor" href="#panneau-scenarios-pro" aria-label="Permalink to &quot;Panneau Scenarios (Pro)&quot;">​</a></h3><ul><li>Parcourir et exécuter les scénarios définis</li><li>Suivre l&#39;exécution du DAG</li></ul><h2 id="charger-des-donnees-depuis-gispulse" tabindex="-1">Charger des données depuis GISPulse <a class="header-anchor" href="#charger-des-donnees-depuis-gispulse" aria-label="Permalink to &quot;Charger des données depuis GISPulse&quot;">​</a></h2><h3 id="via-ogc-api-features" tabindex="-1">Via OGC API Features <a class="header-anchor" href="#via-ogc-api-features" aria-label="Permalink to &quot;Via OGC API Features&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Panneau Datasets → sélectionner un dataset → Charger (OGC)</span></span></code></pre></div><p>La layer est chargée dans QGIS comme une layer vecteur WFS standard. Supporte les filtres bbox et attributaires.</p><h3 id="via-mvt-tuiles-vectorielles" tabindex="-1">Via MVT (tuiles vectorielles) <a class="header-anchor" href="#via-mvt-tuiles-vectorielles" aria-label="Permalink to &quot;Via MVT (tuiles vectorielles)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Panneau Datasets → sélectionner un dataset → Charger (MVT)</span></span></code></pre></div><p>Idéal pour les datasets &gt; 100 000 features. La layer est chargée comme une layer tuile vectorielle MapLibre.</p><p>URL du endpoint MVT :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:8001/ogc/collections/{dataset_id}/tiles/{z}/{x}/{y}.mvt</span></span></code></pre></div><h3 id="via-postgis-direct-pro" tabindex="-1">Via PostGIS direct (Pro) <a class="header-anchor" href="#via-postgis-direct-pro" aria-label="Permalink to &quot;Via PostGIS direct (Pro)&quot;">​</a></h3><p>Quand une session PostGIS est active, le plugin peut charger les tables PostGIS directement via la connexion PostgreSQL de QGIS. Les couches restent synchronisées avec le backend.</p><h2 id="executer-un-job-depuis-qgis" tabindex="-1">Exécuter un job depuis QGIS <a class="header-anchor" href="#executer-un-job-depuis-qgis" aria-label="Permalink to &quot;Exécuter un job depuis QGIS&quot;">​</a></h2><ol><li>Sélectionner un dataset dans le panneau Datasets</li><li>Aller dans le panneau Jobs</li><li>Choisir les règles à appliquer (ou un scénario)</li><li>Cliquer <strong>Exécuter</strong></li><li>Suivre la progression</li><li>Une fois terminé : <strong>Charger le résultat</strong> pour ajouter la layer dans QGIS</li></ol><h2 id="outils-de-geotraitement" tabindex="-1">Outils de géotraitement <a class="header-anchor" href="#outils-de-geotraitement" aria-label="Permalink to &quot;Outils de géotraitement&quot;">​</a></h2><p>Le plugin expose 3 outils dans la <strong>Boîte à outils de traitement QGIS</strong> :</p><table tabindex="0"><thead><tr><th>Outil</th><th>Description</th></tr></thead><tbody><tr><td><code>GISPulse — Run Rules</code></td><td>Exécuter des règles sur la layer active</td></tr><tr><td><code>GISPulse — Upload Dataset</code></td><td>Uploader la layer active vers GISPulse</td></tr><tr><td><code>GISPulse — Export Result</code></td><td>Télécharger le résultat d&#39;un job</td></tr></tbody></table><h2 id="depannage" tabindex="-1">Dépannage <a class="header-anchor" href="#depannage" aria-label="Permalink to &quot;Dépannage&quot;">​</a></h2><h3 id="connection-refused" tabindex="-1">&quot;Connection refused&quot; <a class="header-anchor" href="#connection-refused" aria-label="Permalink to &quot;&quot;Connection refused&quot;&quot;">​</a></h3><p>Vérifiez que <code>gispulse portal</code> tourne sur le port indiqué.</p><h3 id="unauthorized" tabindex="-1">&quot;Unauthorized&quot; <a class="header-anchor" href="#unauthorized" aria-label="Permalink to &quot;&quot;Unauthorized&quot;&quot;">​</a></h3><p>Vérifiez la clé API dans les paramètres du plugin (<strong>Extensions → GISPulse → Settings</strong>).</p><h3 id="layers-mvt-vides" tabindex="-1">Layers MVT vides <a class="header-anchor" href="#layers-mvt-vides" aria-label="Permalink to &quot;Layers MVT vides&quot;">​</a></h3><p>Le endpoint MVT nécessite que le dataset soit indexé côté serveur. Essayez d&#39;abord le chargement OGC.</p><h2 id="developpement-du-plugin" tabindex="-1">Développement du plugin <a class="header-anchor" href="#developpement-du-plugin" aria-label="Permalink to &quot;Développement du plugin&quot;">​</a></h2><p>Voir <a href="/gispulse/plugins/developing">Développer un plugin</a> pour contribuer ou créer votre propre plugin GISPulse.</p><p>Code source : <code>clients/qgis/gispulse_qgis/</code></p>`,49)])])}const g=a(n,[["render",l]]);export{h as __pageData,g as default};
